import{_ as a,o as e,c as r,a2 as d}from"./chunks/framework.Cr-Z7ngm.js";const c=JSON.parse('{"title":"资金流向","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"market-data/money-flow.md","filePath":"zh-CN/market-data/money-flow.md"}'),o={name:"market-data/money-flow.md"};function l(h,t,i,n,s,p){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="资金流向" tabindex="-1">资金流向 <a class="header-anchor" href="#资金流向" aria-label="Permalink to &quot;资金流向&quot;">​</a></h1><p>资金流向数据展示南向（港股通）和北向（沪深港通）资金的实时动态，入口在「市场」Tab → 「市场」子 Tab。</p><h2 id="页面切换" tabindex="-1">页面切换 <a class="header-anchor" href="#页面切换" aria-label="Permalink to &quot;页面切换&quot;">​</a></h2><p>顶部市场 Tab：<strong>沪深港通 / 港股 / 沪深 / 新加坡 / 美股</strong></p><hr><h2 id="南向资金-港股通" tabindex="-1">南向资金（港股通） <a class="header-anchor" href="#南向资金-港股通" aria-label="Permalink to &quot;南向资金（港股通）&quot;">​</a></h2><p>内地资金通过港股通买卖港股的资金流向，分为：</p><ul><li><strong>港股通（沪）</strong>：通过上交所渠道</li><li><strong>港股通（深）</strong>：通过深交所渠道</li></ul><h3 id="展示数据" tabindex="-1">展示数据 <a class="header-anchor" href="#展示数据" aria-label="Permalink to &quot;展示数据&quot;">​</a></h3><table tabindex="0"><thead><tr><th>数据项</th><th>说明</th></tr></thead><tbody><tr><td>成交净买入</td><td>当日净买入金额（买入 - 卖出）</td></tr><tr><td>资金流向</td><td>累计净流入趋势</td></tr><tr><td>剩余额度</td><td>当日剩余可用额度</td></tr><tr><td>南向累计净买入</td><td>历史累计净买入金额</td></tr></tbody></table><p>港股通每日额度为人民币 520 亿元（沪深各 260 亿元）。额度用完后当日不再接受新买单，但卖单不受限制；「剩余额度」实时反映当日已用情况。</p><h3 id="流向趋势图" tabindex="-1">流向趋势图 <a class="header-anchor" href="#流向趋势图" aria-label="Permalink to &quot;流向趋势图&quot;">​</a></h3><p>全天分时流向折线图，可叠加恒生指数走势，直观对比资金动向与大盘关系。</p><p>时间范围切换：<strong>当日 / 近 5 日 / 近 20 日 / 近 60 日</strong></p><hr><h2 id="北向资金-沪深港通" tabindex="-1">北向资金（沪深港通） <a class="header-anchor" href="#北向资金-沪深港通" aria-label="Permalink to &quot;北向资金（沪深港通）&quot;">​</a></h2><p>境外资金通过沪深港通买卖 A 股的资金流向。北向资金数据存在约 15 分钟延迟（港交所规定），非实时数据；页面时间戳反映最后更新时间。</p><table tabindex="0"><thead><tr><th>数据项</th><th>说明</th></tr></thead><tbody><tr><td>实时净流向</td><td>当日实时净买入金额</td></tr><tr><td>持股记录</td><td>北向资金持有的 A 股明细</td></tr></tbody></table><hr><h2 id="十大成交" tabindex="-1">十大成交 <a class="header-anchor" href="#十大成交" aria-label="Permalink to &quot;十大成交&quot;">​</a></h2><p>港股/A 股当日成交金额最大的十只股票，显示：</p><ul><li>股票名称与代码</li><li>净买卖股数</li><li>净流入金额（正为净买入，负为净卖出；负数表示当日净卖出，资金净流出市场）</li></ul><p>如需查看南向资金对特定个股的影响，可在个股详情页查看该股票的南向持股比例及近期变动趋势。</p><hr><h2 id="数据更新频率" tabindex="-1">数据更新频率 <a class="header-anchor" href="#数据更新频率" aria-label="Permalink to &quot;数据更新频率&quot;">​</a></h2><p>数据在交易时段内持续更新，页面显示具体更新时间戳（如「04.02 10:39 更新」），一般为分钟级更新。</p>',26)])])}const u=a(o,[["render",l]]);export{c as __pageData,u as default};
